   402→    try {
   403→      while (true) {
   404→        const { done, value } = await reader.read();
   405→        if (done) break;
   406→
   407→        buffer += decoder.decode(value, { stream: true });
   408→        const lines = buffer.split('\n');
   409→        buffer = lines.pop() || '';
