   498→    const summary = msg['summary'] as Record<string, unknown>;
   499→
   500→    return {
   501→      type: 'RESULT',
   502→      requestId: msg['request_id'] as string,
   503→      status: msg['status'] as 'OPTIMAL' | 'FEASIBLE' | 'FALLBACK' | 'INFEASIBLE',
   504→      solveTimeMs: msg['solve_time_ms'] as number,
