  name: string;
  /** Job data payload */
  data: T;
  /** Job attempt number (1-based) */
  attemptsMade: number;
  /** Update job progress (0-100) */
  updateProgress: (progress: number | object) => Promise<void>;
  /** Add log message to job */
  log: (message: string) => Promise<void>;
}

/**
